/**
 * region-names.js — canonical human-readable name for all 192 Axona regions.
 *
 * Each 8-bit S2 region code (utils/s2.js — codes [0,192)) has exactly ONE name,
 * so a region always presents the same label (no location-dependent flip-flop).
 * The name is derived per region by scripts/gen-region-names.mjs and frozen here.
 *
 * REGION_NAMES[code] = name (a string). Generated by collapsing each cell's two
 * S2 sub-cells to one name: an ocean-half beside a land-half takes the land
 * name; a multi-country cell takes its dominant city; homogeneous cells keep
 * their single name.
 *
 * Conventions (enforced by test/smoke_region_names.js):
 *   • names match /^[a-z0-9_]{1,8}$/  (lowercase, no spaces)
 *   • short names — country, else its largest city (colombia, moscow, kenya); ≤8 chars
 *   • open ocean → "<oce3>_<hex>"  (pac_68, atl_0a, ind_22, sou_a3, arc_44)
 *   • a name is usually unique to one code, but an area larger than one cell MAY
 *     span adjacent codes (e.g. "centrlam" covers 0x84 and 0x8f). regionCode()
 *     then returns the canonical (lowest) code for that name.
 */

import { geoCellId, geoCellCenter, isValidCellId, S2_CELL_COUNT } from './s2.js';

